// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract DogeFood is ERC721, Ownable {
    uint256 private _tokenIdCounter;
    uint256 public constant MAX_SUPPLY = 420;
    string public baseTokenURI;

    event DogeNFTMinted(address indexed to, uint256 indexed tokenId);

    constructor(
        string memory _name,
        string memory _symbol,
        string memory _baseTokenURI,
        address initialOwner
    ) ERC721(_name, _symbol) Ownable(initialOwner) {
        baseTokenURI = _baseTokenURI;
    }

    function mint(address to) public onlyOwner {
        require(_tokenIdCounter < MAX_SUPPLY, "Max supply reached");
        uint256 tokenId = _tokenIdCounter;
        _tokenIdCounter++;
        _safeMint(to, tokenId);
        emit DogeNFTMinted(to, tokenId);
    }

    // Public minting function for game mechanics
    function mintTreat(address to) public {
        require(_tokenIdCounter < MAX_SUPPLY, "Max supply reached");
        require(to != address(0), "Cannot mint to zero address");

        uint256 tokenId = _tokenIdCounter;
        _tokenIdCounter++;
        _safeMint(to, tokenId);
        emit DogeNFTMinted(to, tokenId);
    }

    function batchMint(address[] calldata addresses) external onlyOwner {
        require(_tokenIdCounter + addresses.length <= MAX_SUPPLY, "Would exceed max supply");

        for (uint256 i = 0; i < addresses.length; i++) {
            uint256 tokenId = _tokenIdCounter;
            _tokenIdCounter++;
            _safeMint(addresses[i], tokenId);
            emit DogeNFTMinted(addresses[i], tokenId);
        }
    }

    function totalSupply() public view returns (uint256) {
        return _tokenIdCounter;
    }

    function setBaseURI(string memory _baseTokenURI) external onlyOwner {
        baseTokenURI = _baseTokenURI;
    }

    function _baseURI() internal view override returns (string memory) {
        return baseTokenURI;
    }
}

contracts/GamePaymentGateway.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IBondingCurveGraduation {
    function isGraduated(address token) external view returns (bool);
}

/**
 * @title GamePaymentGateway
 * @dev Single entry point for in-game spending that isn't LAB's existing
 * reward flow: extra lives, marketplace purchases, Lab Surge wagers,
 * tournament entries, and anything future utilities add. Accepts native
 * DOGE, the LAB token, or any token that has graduated off its bonding
 * curve - unlaunched or still-bonding tokens are rejected, so a curve can't
 * be used for in-game spend before the market has actually vetted it.
 *
 * This contract doesn't track game state (lives, wager pots, purchase
 * history) - that lives in the backend's Game Payments collection, keyed
 * off the payment_id in the PaymentReceived event below. It just verifies
 * the payment is in an accepted currency and forwards it to LauncherTreasury.
 * Payouts (e.g. a Lab Surge winner receiving the pot) go back out the same
 * way any protocol spend does, as a Treasury owner withdrawal, rather than
 * this contract holding funds in escrow.
 */
contract GamePaymentGateway is Ownable, ReentrancyGuard {
    address public immutable labToken;
    address public bondingCurve;
    address payable public treasury;

    uint256 public nextPaymentId = 1;

    event BondingCurveUpdated(address indexed bondingCurve);
    event TreasuryUpdated(address indexed treasury);
    event PaymentReceived(
        uint256 indexed paymentId,
        address indexed payer,
        address token,
        uint256 amount,
        string feature
    );

    constructor(address labToken_, address bondingCurve_, address payable treasury_, address owner_) Ownable(owner_) {
        require(labToken_ != address(0), "GamePaymentGateway: bad LAB token");
        require(bondingCurve_ != address(0), "GamePaymentGateway: bad bonding curve");
        require(treasury_ != address(0), "GamePaymentGateway: bad treasury");
        labToken = labToken_;
        bondingCurve = bondingCurve_;
        treasury = treasury_;
    }

    function setBondingCurve(address bondingCurve_) external onlyOwner {
        require(bondingCurve_ != address(0), "GamePaymentGateway: bad bonding curve");
        bondingCurve = bondingCurve_;
        emit BondingCurveUpdated(bondingCurve_);
    }

    function setTreasury(address payable treasury_) external onlyOwner {
        require(treasury_ != address(0), "GamePaymentGateway: bad treasury");
        treasury = treasury_;
        emit TreasuryUpdated(treasury_);
    }

    function isAcceptedToken(address token) public view returns (bool) {
        if (token == address(0) || token == labToken) return true;
        return IBondingCurveGraduation(bondingCurve).isGraduated(token);
    }

    /// @param token address(0) for native DOGE, otherwise an ERC20 (LAB or a
    /// graduated launcher token).
    /// @param amount required for ERC20 payments; ignored for native DOGE
    /// (msg.value is used instead).
    /// @param feature short tag identifying what's being paid for, e.g.
    /// "extra_life", "marketplace:<listingId>", "lab_surge:<matchId>".
    function pay(address token, uint256 amount, string calldata feature) external payable nonReentrant returns (uint256 paymentId) {
        require(bytes(feature).length > 0, "GamePaymentGateway: feature required");
        require(isAcceptedToken(token), "GamePaymentGateway: token not accepted");

        uint256 paidAmount;
        if (token == address(0)) {
            require(msg.value > 0, "GamePaymentGateway: send DOGE");
            paidAmount = msg.value;
            (bool ok, ) = treasury.call{value: paidAmount}("");
            require(ok, "GamePaymentGateway: DOGE forward failed");
        } else {
            require(msg.value == 0, "GamePaymentGateway: unexpected DOGE sent");
            require(amount > 0, "GamePaymentGateway: amount must be > 0");
            paidAmount = amount;
            require(IERC20(token).transferFrom(msg.sender, treasury, paidAmount), "GamePaymentGateway: token transfer failed");
        }

        paymentId = nextPaymentId++;
        emit PaymentReceived(paymentId, msg.sender, token, paidAmount, feature);
    }
}

contracts/GraduationManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

interface IDexRouter {
    function factory() external view returns (address);
    function WETH() external view returns (address);
    function addLiquidityETH(
        address token,
        uint256 amountTokenDesired,
        uint256 amountTokenMin,
        uint256 amountETHMin,
        address to,
        uint256 deadline
    ) external payable returns (uint256 amountToken, uint256 amountETH, uint256 liquidity);
}

interface IDexFactory {
    function getPair(address tokenA, address tokenB) external view returns (address pair);
}

interface ILaunchTokenGraduation {
    function activateSwapFee(address pair) external;
}

/**
 * @title GraduationManager
 * @dev Receives a token's remaining supply and raised DOGE from BondingCurve
 * once it hits its target, and turns that into a permanently locked DEX
 * position: it adds the liquidity, burns the LP tokens to a dead address
 * (the simplest, most trustless form of "Liquidity Locked" - nobody, not
 * even DogeFood Lab, can ever be the one who pulls it), and flips on the
 * token's post-graduation swap fee against the new pair.
 *
 * The DEX router address is NOT hardcoded - DogeOS's router/factory
 * addresses should be set via setRouter() once known. graduate() reverts
 * until that's configured, so a missing router blocks graduation loudly
 * instead of silently sending funds somewhere wrong.
 */
contract GraduationManager is Ownable {
    address public constant BURN_ADDRESS = 0x000000000000000000000000000000000000dEaD;

    address public bondingCurve;
    IDexRouter public router;

    /// @dev Basis points of slippage tolerance allowed when seeding the pool
    /// (e.g. 300 = 3%). Applies to both the token and DOGE side.
    uint256 public liquiditySlippageBps = 300;
    uint256 public constant BPS_DENOMINATOR = 10_000;

    mapping(address => address) public pairOf; // launched token => DEX pair

    event RouterUpdated(address indexed router);
    event BondingCurveUpdated(address indexed bondingCurve);
    event TokenGraduated(address indexed token, address indexed pair, address creator, uint256 dogeAmount, uint256 tokenAmount, uint256 liquidity);

    modifier onlyBondingCurve() {
        require(msg.sender == bondingCurve, "GraduationManager: not bonding curve");
        _;
    }

    constructor(address bondingCurve_, address owner_) Ownable(owner_) {
        require(bondingCurve_ != address(0), "GraduationManager: bad bonding curve");
        bondingCurve = bondingCurve_;
    }

    function setBondingCurve(address bondingCurve_) external onlyOwner {
        require(bondingCurve_ != address(0), "GraduationManager: bad bonding curve");
        bondingCurve = bondingCurve_;
        emit BondingCurveUpdated(bondingCurve_);
    }

    /// @dev Must be called with DogeOS's live DEX router address before the
    /// first token can graduate.
    function setRouter(address router_) external onlyOwner {
        require(router_ != address(0), "GraduationManager: bad router");
        router = IDexRouter(router_);
        emit RouterUpdated(router_);
    }

    function setLiquiditySlippageBps(uint256 bps) external onlyOwner {
        require(bps <= 2_000, "GraduationManager: slippage too high"); // hard cap at 20%
        liquiditySlippageBps = bps;
    }

    /// @dev Called once by BondingCurve when a curve's graduation target is
    /// reached. Expects tokenAmount of `token` to already have been
    /// transferred here, and the DOGE amount to arrive as msg.value.
    function graduate(address token, uint256 tokenAmount, address creator) external payable onlyBondingCurve {
        require(address(router) != address(0), "GraduationManager: router not configured");
        require(msg.value > 0 && tokenAmount > 0, "GraduationManager: nothing to seed pool with");
        require(pairOf[token] == address(0), "GraduationManager: already graduated");

        uint256 tokenMin = tokenAmount - ((tokenAmount * liquiditySlippageBps) / BPS_DENOMINATOR);
        uint256 dogeMin = msg.value - ((msg.value * liquiditySlippageBps) / BPS_DENOMINATOR);

        require(IERC20(token).approve(address(router), tokenAmount), "GraduationManager: approve failed");

        (, , uint256 liquidity) = router.addLiquidityETH{value: msg.value}(
            token,
            tokenAmount,
            tokenMin,
            dogeMin,
            BURN_ADDRESS,
            block.timestamp + 15 minutes
        );

        address pair = IDexFactory(router.factory()).getPair(token, router.WETH());
        require(pair != address(0), "GraduationManager: pair not found");
        pairOf[token] = pair;

        ILaunchTokenGraduation(token).activateSwapFee(pair);

        emit TokenGraduated(token, pair, creator, msg.value, tokenAmount, liquidity);

        // Any dust left over from addLiquidityETH's min-amount rounding stays
        // in this contract; sweep() lets the owner recover it.
    }

    /// @dev Recovers rounding dust left behind after addLiquidityETH (it can
    /// use slightly less than the full amounts offered). Does not touch
    /// tokens/DOGE mid-graduation since graduate() is a single atomic call.
    function sweep(address token, address to, uint256 amount) external onlyOwner {
        require(to != address(0), "GraduationManager: bad recipient");
        if (token == address(0)) {
            (bool ok, ) = payable(to).call{value: amount}("");
            require(ok, "GraduationManager: DOGE sweep failed");
        } else {
            require(IERC20(token).transfer(to, amount), "GraduationManager: token sweep failed");
        }
    }

    receive() external payable {}
}

contracts/LABToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract LABToken is ERC20, Ownable {
    uint256 public constant TOTAL_SUPPLY = 420_000_000 * 10**18; // 420M tokens

    uint256 public constant COMMUNITY_ALLOCATION = 294_000_000 * 10**18; // 70%
    uint256 public constant PUBLIC_SALE_ALLOCATION = 42_000_000 * 10**18; // 10%
    uint256 public constant LIQUIDITY_ALLOCATION = 42_000_000 * 10**18; // 10%
    uint256 public constant MARKETING_ALLOCATION = 21_000_000 * 10**18; // 5%
    uint256 public constant TEAM_ALLOCATION = 21_000_000 * 10**18; // 5%

    address public rewardDistributor;
    address public teamVesting;

    uint256 public teamCliffEnd;
    uint256 public teamVestingEnd;
    uint256 public teamTokensReleased;

    event TeamTokensReleased(uint256 amount);
    event RewardDistributorUpdated(address indexed newDistributor);

    constructor(
        address _owner,
        address _rewardDistributor,
        address _publicSale,
        address _liquidity,
        address _marketing,
        address _teamVesting
    ) ERC20("LAB Token", "LAB") Ownable(_owner) {
        rewardDistributor = _rewardDistributor;
        teamVesting = _teamVesting;

        // Set team vesting schedule: 12-month cliff, 24-month vesting
        teamCliffEnd = block.timestamp + 365 days;
        teamVestingEnd = teamCliffEnd + 365 days;

        // Mint allocations
        if (_rewardDistributor != address(0)) {
            _mint(_rewardDistributor, COMMUNITY_ALLOCATION);
        } else {
            _mint(address(this), COMMUNITY_ALLOCATION); // Hold until distributor is set
        }
        _mint(_publicSale, PUBLIC_SALE_ALLOCATION);
        _mint(_liquidity, LIQUIDITY_ALLOCATION);
        _mint(_marketing, MARKETING_ALLOCATION);
        _mint(address(this), TEAM_ALLOCATION); // Hold team tokens for vesting
    }

    function setRewardDistributor(address _rewardDistributor) external onlyOwner {
        require(_rewardDistributor != address(0), "Invalid address");

        // If community tokens are held by contract, transfer to distributor
        if (rewardDistributor == address(0) && balanceOf(address(this)) >= COMMUNITY_ALLOCATION) {
            _transfer(address(this), _rewardDistributor, COMMUNITY_ALLOCATION);
        }

        rewardDistributor = _rewardDistributor;
        emit RewardDistributorUpdated(_rewardDistributor);
    }

    function releaseTeamTokens() external {
        require(block.timestamp >= teamCliffEnd, "Cliff period not ended");
        require(teamTokensReleased < TEAM_ALLOCATION, "All team tokens released");

        uint256 releasable = _calculateReleasableAmount();
        require(releasable > 0, "No tokens to release");

        teamTokensReleased += releasable;
        _transfer(address(this), teamVesting, releasable);

        emit TeamTokensReleased(releasable);
    }

    function _calculateReleasableAmount() private view returns (uint256) {
        if (block.timestamp < teamCliffEnd) {
            return 0;
        }

        uint256 totalReleasable;
        if (block.timestamp >= teamVestingEnd) {
            totalReleasable = TEAM_ALLOCATION;
        } else {
            uint256 vestingDuration = teamVestingEnd - teamCliffEnd;
            uint256 elapsedTime = block.timestamp - teamCliffEnd;
            totalReleasable = (TEAM_ALLOCATION * elapsedTime) / vestingDuration;
        }

        return totalReleasable - teamTokensReleased;
    }

    function getReleasableAmount() external view returns (uint256) {
        return _calculateReleasableAmount();
    }
}

contracts/LauncherTreasury.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title LauncherTreasury
 * @dev Collects DogeFood Lab's share of every fee the launcher generates:
 * the full 2% bonding-curve fee before a token graduates, the 1% protocol
 * half of the swap fee after graduation (paid in-kind, in whatever token
 * traded), and game payments routed through GamePaymentGateway (DOGE, LAB,
 * or any graduated token). It never needs to know which of those a given
 * deposit came from - it just holds native DOGE and ERC20 balances and lets
 * the owner withdraw them. Lab Surge payouts and any other "send funds back
 * out" flow are also just owner withdrawals from here, rather than a
 * separate escrow contract.
 */
contract LauncherTreasury is Ownable {
    event NativeReceived(address indexed from, uint256 amount);
    event NativeWithdrawn(address indexed to, uint256 amount);
    event TokenWithdrawn(address indexed token, address indexed to, uint256 amount);

    constructor(address owner_) Ownable(owner_) {}

    receive() external payable {
        emit NativeReceived(msg.sender, msg.value);
    }

    function withdrawNative(address payable to, uint256 amount) external onlyOwner {
        require(to != address(0), "LauncherTreasury: bad recipient");
        require(amount <= address(this).balance, "LauncherTreasury: insufficient balance");
        (bool ok, ) = to.call{value: amount}("");
        require(ok, "LauncherTreasury: transfer failed");
        emit NativeWithdrawn(to, amount);
    }

    function withdrawToken(address token, address to, uint256 amount) external onlyOwner {
        require(to != address(0), "LauncherTreasury: bad recipient");
        require(IERC20(token).transfer(to, amount), "LauncherTreasury: transfer failed");
        emit TokenWithdrawn(token, to, amount);
    }
}

