// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "./LaunchToken.sol";

interface IBondingCurveRegister {
    function registerToken(address token, address creator) external;
}

interface IRoyaltyDistributorRegister {
    function registerToken(address token, address creator) external;
}

/**
 * @title LaunchpadFactory
 * @dev Entry point for "create a token in under a minute": takes a name and
 * symbol, deploys a LaunchToken with the full fixed supply minted straight
 * to BondingCurve, and registers it with both BondingCurve (so it can be
 * bought and sold) and RoyaltyDistributor (so the creator has somewhere to
 * claim from after graduation). There's no launch fee - the only cost is
 * gas. Everything else in the spec's "Create Token" form (description,
 * logo, website, X, Telegram) is off-chain metadata that the backend stores
 * against the token address this contract emits, not on-chain state.
 */
contract LaunchpadFactory is Ownable {
    uint256 public constant TOTAL_SUPPLY = 1_000_000_000 ether; // fixed for every launch, no presale/team allocation

    address public immutable bondingCurve;
    address public immutable royaltyDistributor;
    address public immutable treasury;
    address public immutable graduationManager;

    address[] public allTokens;

    event TokenLaunched(
        address indexed token,
        address indexed creator,
        string name,
        string symbol,
        uint256 totalSupply,
        uint256 index
    );

    constructor(
        address bondingCurve_,
        address royaltyDistributor_,
        address treasury_,
        address graduationManager_,
        address owner_
    ) Ownable(owner_) {
        require(bondingCurve_ != address(0), "LaunchpadFactory: bad bonding curve");
        require(royaltyDistributor_ != address(0), "LaunchpadFactory: bad royalty distributor");
        require(treasury_ != address(0), "LaunchpadFactory: bad treasury");
        require(graduationManager_ != address(0), "LaunchpadFactory: bad graduation manager");
        bondingCurve = bondingCurve_;
        royaltyDistributor = royaltyDistributor_;
        treasury = treasury_;
        graduationManager = graduationManager_;
    }

    function createToken(string calldata name, string calldata symbol) external returns (address token) {
        require(bytes(name).length > 0, "LaunchpadFactory: name required");
        require(bytes(symbol).length > 0, "LaunchpadFactory: symbol required");

        token = address(
            new LaunchToken(
                name,
                symbol,
                TOTAL_SUPPLY,
                msg.sender,
                bondingCurve,
                treasury,
                royaltyDistributor,
                graduationManager
            )
        );

        IBondingCurveRegister(bondingCurve).registerToken(token, msg.sender);
        IRoyaltyDistributorRegister(royaltyDistributor).registerToken(token, msg.sender);

        allTokens.push(token);

        emit TokenLaunched(token, msg.sender, name, symbol, TOTAL_SUPPLY, allTokens.length - 1);
    }

    function totalTokensLaunched() external view returns (uint256) {
        return allTokens.length;
    }
}

contracts/LaunchToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";

/**
 * @title LaunchToken
 * @dev ERC20 deployed by LaunchpadFactory for every Lab Launcher token. The
 * full supply is minted straight to BondingCurve at creation - there is no
 * team or presale allocation, and this contract has no owner and no
 * privileged mint/pause/blacklist functions. That is what backs the
 * "Ownership Renounced" / "Contract Verified" trust badges on the token
 * profile: it isn't a claim, it's just true by construction.
 *
 * A swap fee (2%, split 1% treasury / 1% creator royalty) applies ONLY to
 * transfers that touch the registered AMM pair address. Wallet-to-wallet
 * transfers are always free, and bonding-curve trades are never taxed here -
 * BondingCurve charges its own 2% on every buy/sell instead. The AMM pair is
 * set exactly once, by GraduationManager, at the moment liquidity is locked
 * and trading moves to the DEX - so the swap fee only ever activates for a
 * token that has actually graduated.
 */
contract LaunchToken is ERC20 {
    uint256 public constant SWAP_FEE_BPS = 200; // 2% total on AMM-pair transfers
    uint256 public constant BPS_DENOMINATOR = 10_000;

    address public immutable creator;
    address public immutable factory;
    address public immutable treasury;
    address public immutable royaltyDistributor;
    address public immutable graduationManager;

    address public ammPair;
    bool public feesActive;

    event SwapFeeActivated(address indexed pair);

    modifier onlyGraduationManager() {
        require(msg.sender == graduationManager, "LaunchToken: not graduation manager");
        _;
    }

    constructor(
        string memory name_,
        string memory symbol_,
        uint256 totalSupply_,
        address creator_,
        address curveHolder_,
        address treasury_,
        address royaltyDistributor_,
        address graduationManager_
    ) ERC20(name_, symbol_) {
        require(creator_ != address(0), "LaunchToken: bad creator");
        require(curveHolder_ != address(0), "LaunchToken: bad curve");
        require(treasury_ != address(0), "LaunchToken: bad treasury");
        require(royaltyDistributor_ != address(0), "LaunchToken: bad royalty distributor");
        require(graduationManager_ != address(0), "LaunchToken: bad graduation manager");

        creator = creator_;
        factory = msg.sender;
        treasury = treasury_;
        royaltyDistributor = royaltyDistributor_;
        graduationManager = graduationManager_;

        _mint(curveHolder_, totalSupply_);
    }

    /// @dev Called once by GraduationManager right after it locks liquidity and
    /// creates the DEX pair for this token. Turns on the post-graduation swap fee.
    function activateSwapFee(address pair_) external onlyGraduationManager {
        require(!feesActive, "LaunchToken: already activated");
        require(pair_ != address(0), "LaunchToken: bad pair");
        ammPair = pair_;
        feesActive = true;
        emit SwapFeeActivated(pair_);
    }

    function _update(address from, address to, uint256 value) internal override {
        if (
            feesActive &&
            value > 0 &&
            from != address(0) &&
            to != address(0) &&
            (from == ammPair || to == ammPair)
        ) {
            uint256 fee = (value * SWAP_FEE_BPS) / BPS_DENOMINATOR;
            if (fee > 0) {
                uint256 creatorShare = fee / 2;
                uint256 treasuryShare = fee - creatorShare;
                super._update(from, treasury, treasuryShare);
                super._update(from, royaltyDistributor, creatorShare);
                value -= fee;
            }
        }
        super._update(from, to, value);
    }
}

contracts/RewardDistributor.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/cryptography/MerkleProof.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract RewardDistributor is Ownable, ReentrancyGuard {
    IERC20 public immutable labToken;

    struct Season {
        bytes32 merkleRoot;
        uint256 startTime;
        uint256 endTime;
        uint256 totalRewards;
        bool active;
        mapping(address => uint256) claimed;
        uint256 totalClaimed;
    }

    mapping(uint256 => Season) public seasons;
    uint256 public currentSeason;
    uint256 public constant UNCLAIMED_PERIOD = 180 days; // 6 months

    event SeasonCreated(uint256 indexed seasonId, bytes32 merkleRoot, uint256 startTime, uint256 endTime, uint256 totalRewards);
    event RewardClaimed(uint256 indexed seasonId, address indexed user, uint256 amount);
    event SeasonClosed(uint256 indexed seasonId, uint256 unclaimedAmount);
    event UnclaimedTokensRecovered(uint256 indexed seasonId, uint256 amount);

    constructor(address _labToken, address _owner) Ownable(_owner) {
        labToken = IERC20(_labToken);
    }

    function createSeason(
        bytes32 _merkleRoot,
        uint256 _startTime,
        uint256 _endTime,
        uint256 _totalRewards
    ) external onlyOwner {
        require(_startTime < _endTime, "Invalid time range");
        require(_endTime > block.timestamp, "End time in past");
        require(_totalRewards > 0, "Invalid reward amount");
        require(labToken.balanceOf(address(this)) >= _totalRewards, "Insufficient balance");

        currentSeason++;
        Season storage season = seasons[currentSeason];
        season.merkleRoot = _merkleRoot;
        season.startTime = _startTime;
        season.endTime = _endTime;
        season.totalRewards = _totalRewards;
        season.active = true;

        emit SeasonCreated(currentSeason, _merkleRoot, _startTime, _endTime, _totalRewards);
    }

    function claimReward(
        uint256 seasonId,
        uint256 amount,
        bytes32[] calldata merkleProof
    ) external nonReentrant {
        Season storage season = seasons[seasonId];
        require(season.active, "Season not active");
        require(block.timestamp >= season.startTime, "Season not started");
        require(block.timestamp <= season.endTime, "Season ended");
        require(season.claimed[msg.sender] == 0, "Already claimed");

        bytes32 leaf = keccak256(abi.encodePacked(msg.sender, amount));
        require(MerkleProof.verify(merkleProof, season.merkleRoot, leaf), "Invalid proof");

        season.claimed[msg.sender] = amount;
        season.totalClaimed += amount;

        require(labToken.transfer(msg.sender, amount), "Transfer failed");

        emit RewardClaimed(seasonId, msg.sender, amount);
    }

    function closeSeason(uint256 seasonId) external onlyOwner {
        Season storage season = seasons[seasonId];
        require(season.active, "Season not active");
        require(block.timestamp > season.endTime + UNCLAIMED_PERIOD, "Unclaimed period not ended");

        season.active = false;
        uint256 unclaimedAmount = season.totalRewards - season.totalClaimed;

        if (unclaimedAmount > 0) {
            // Return unclaimed tokens to treasury (owner)
            require(labToken.transfer(owner(), unclaimedAmount), "Transfer failed");
            emit UnclaimedTokensRecovered(seasonId, unclaimedAmount);
        }

        emit SeasonClosed(seasonId, unclaimedAmount);
    }

    function hasClaimedSeason(uint256 seasonId, address user) external view returns (bool) {
        return seasons[seasonId].claimed[user] > 0;
    }

    function getClaimedAmount(uint256 seasonId, address user) external view returns (uint256) {
        return seasons[seasonId].claimed[user];
    }

    function getSeasonInfo(uint256 seasonId) external view returns (
        bytes32 merkleRoot,
        uint256 startTime,
        uint256 endTime,
        uint256 totalRewards,
        uint256 totalClaimed,
        bool active
    ) {
        Season storage season = seasons[seasonId];
        return (
            season.merkleRoot,
            season.startTime,
            season.endTime,
            season.totalRewards,
            season.totalClaimed,
            season.active
        );
    }

    // Emergency function to recover tokens if needed
    function emergencyWithdraw(uint256 amount) external onlyOwner {
        require(labToken.transfer(owner(), amount), "Transfer failed");
    }
}

contracts/RoyaltyDistributor.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title RoyaltyDistributor
 * @dev Holds each launched token's creator-royalty share of the post-
 * graduation swap fee, and lets that creator claim it. LaunchToken's swap
 * fee sends the creator's half of every taxed transfer directly here as a
 * plain ERC20 transfer - there is no separate bookkeeping call, because a
 * token only ever registers one creator and only its own tax mechanism ever
 * sends it here. That means this contract's current balance of a given
 * token IS that creator's unclaimed royalty, which is what claim() reads.
 */
contract RoyaltyDistributor is Ownable, ReentrancyGuard {
    address public factory;

    mapping(address => address) public creatorOf; // launched token => creator

    event FactoryUpdated(address indexed factory);
    event TokenRegistered(address indexed token, address indexed creator);
    event RoyaltyClaimed(address indexed token, address indexed creator, uint256 amount);

    modifier onlyFactory() {
        require(msg.sender == factory, "RoyaltyDistributor: not factory");
        _;
    }

    constructor(address owner_) Ownable(owner_) {}

    function setFactory(address factory_) external onlyOwner {
        require(factory_ != address(0), "RoyaltyDistributor: bad factory");
        factory = factory_;
        emit FactoryUpdated(factory_);
    }

    /// @dev Called once by LaunchpadFactory when a new token is created.
    function registerToken(address token, address creator_) external onlyFactory {
        require(token != address(0), "RoyaltyDistributor: bad token");
        require(creator_ != address(0), "RoyaltyDistributor: bad creator");
        require(creatorOf[token] == address(0), "RoyaltyDistributor: already registered");
        creatorOf[token] = creator_;
        emit TokenRegistered(token, creator_);
    }

    /// @dev Returns the caller's unclaimed royalty balance for a token.
    function pendingRoyalty(address token) external view returns (uint256) {
        if (creatorOf[token] == address(0)) return 0;
        return IERC20(token).balanceOf(address(this));
    }

    function claim(address token) external nonReentrant {
        require(creatorOf[token] == msg.sender, "RoyaltyDistributor: not creator");
        uint256 amount = IERC20(token).balanceOf(address(this));
        require(amount > 0, "RoyaltyDistributor: nothing to claim");
        require(IERC20(token).transfer(msg.sender, amount), "RoyaltyDistributor: transfer failed");
        emit RoyaltyClaimed(token, msg.sender, amount);
    }
}

contracts/TreatNFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Enumerable.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title TreatNFT
 * @dev NFT contract for DogeFood Lab treat outcomes with metadata storage
 */
contract TreatNFT is ERC721, ERC721Enumerable, ERC721URIStorage, Ownable {
    uint256 private _nextTokenId;

    // Treat metadata structure
    struct TreatMetadata {
        string rarity;           // "Common", "Rare", "Epic", "Legendary"
        string[] ingredients;    // Array of ingredient names used
        uint256 ingredientCount; // Number of ingredients used
        uint256 playerLevel;     // Player level when treat was created
        uint256 seasonId;        // Season ID when treat was created
        uint256 createdAt;       // Timestamp of creation
        address creator;         // Address of the treat creator
        bool isReady;           // Whether treat has completed brewing
        string treatName;        // Name of the treat
    }

    // Mapping from token ID to treat metadata
    mapping(uint256 => TreatMetadata) public treatMetadata;

    // Mapping from creator address to their treat count by season
    mapping(address => mapping(uint256 => uint256)) public creatorSeasonTreats;

    // Mapping from season ID to total treats created
    mapping(uint256 => uint256) public seasonTreatCounts;

    // Mapping from rarity to total count
    mapping(string => uint256) public rarityTotals;

    // Events
    event TreatCreated(
        uint256 indexed tokenId,
        address indexed creator,
        string rarity,
        uint256 ingredientCount,
        uint256 seasonId,
        string treatName
    );

    event TreatCompleted(
        uint256 indexed tokenId,
        address indexed creator,
        uint256 completedAt
    );

    constructor(address initialOwner) ERC721("DogeFood Lab Treats", "TREAT") Ownable(initialOwner) {}

    /**
     * @dev Mint a new treat NFT with complete metadata
     * @param to Address to mint the NFT to
     * @param rarity Rarity of the treat ("Common", "Rare", "Epic", "Legendary")
     * @param ingredients Array of ingredient names used
     * @param playerLevel Player's level when creating the treat
     * @param seasonId Current season ID
     * @param treatName Name of the created treat
     * @return tokenId The ID of the newly minted NFT
     */
    function mintTreat(
        address to,
        string memory rarity,
        string[] memory ingredients,
        uint256 playerLevel,
        uint256 seasonId,
        string memory treatName
    ) public onlyOwner returns (uint256) {
        uint256 tokenId = _nextTokenId++;

        // Mint the NFT
        _safeMint(to, tokenId);

        // Store metadata
        treatMetadata[tokenId] = TreatMetadata({
            rarity: rarity,
            ingredients: ingredients,
            ingredientCount: ingredients.length,
            playerLevel: playerLevel,
            seasonId: seasonId,
            createdAt: block.timestamp,
            creator: to,
            isReady: false, // Initially not ready (brewing)
            treatName: treatName
        });

        // Update counters
        creatorSeasonTreats[to][seasonId]++;
        seasonTreatCounts[seasonId]++;
        rarityTotals[rarity]++;

        emit TreatCreated(
            tokenId,
            to,
            rarity,
            ingredients.length,
            seasonId,
            treatName
        );

        return tokenId;
    }

    /**
     * @dev Mark a treat as completed (finished brewing)
     * @param tokenId ID of the treat to mark as completed
     */
    function completeTreat(uint256 tokenId) public onlyOwner {
        require(_ownerOf(tokenId) != address(0), "TreatNFT: treat does not exist");
        require(!treatMetadata[tokenId].isReady, "TreatNFT: treat already completed");

        treatMetadata[tokenId].isReady = true;

        emit TreatCompleted(
            tokenId,
            treatMetadata[tokenId].creator,
            block.timestamp
        );
    }

    /**
     * @dev Batch mint multiple treats (for efficiency)
     * @param recipients Array of addresses to mint to
     * @param rarities Array of rarities for each treat
     * @param ingredientCounts Array of ingredient counts for each treat
     * @param playerLevels Array of player levels for each treat
     * @param seasonId Current season ID (same for all)
     */
    function batchMintTreats(
        address[] memory recipients,
        string[] memory rarities,
        uint256[] memory ingredientCounts,
        uint256[] memory playerLevels,
        uint256 seasonId
    ) public onlyOwner {
        require(
            recipients.length == rarities.length &&
            rarities.length == ingredientCounts.length &&
            ingredientCounts.length == playerLevels.length,
            "TreatNFT: array length mismatch"
        );

        for (uint256 i = 0; i < recipients.length; i++) {
            uint256 tokenId = _nextTokenId++;

            _safeMint(recipients[i], tokenId);

            // Create empty ingredients array for batch minting
            string[] memory emptyIngredients = new string[](0);

            treatMetadata[tokenId] = TreatMetadata({
                rarity: rarities[i],
                ingredients: emptyIngredients,
                ingredientCount: ingredientCounts[i],
                playerLevel: playerLevels[i],
                seasonId: seasonId,
                createdAt: block.timestamp,
                creator: recipients[i],
                isReady: false,
                treatName: "Batch Treat"
            });

            creatorSeasonTreats[recipients[i]][seasonId]++;
            seasonTreatCounts[seasonId]++;
            rarityTotals[rarities[i]]++;
        }
    }

    /**
     * @dev Get complete metadata for a treat
     * @param tokenId ID of the treat
     * @return Complete TreatMetadata struct
     */
    function getTreatMetadata(uint256 tokenId) public view returns (TreatMetadata memory) {
        require(_ownerOf(tokenId) != address(0), "TreatNFT: treat does not exist");
        return treatMetadata[tokenId];
    }

    /**
     * @dev Get treats by creator address
     * @param creator Address of the creator
     * @return Array of token IDs owned by the creator
     */
    function getTreatsByCreator(address creator) public view returns (uint256[] memory) {
        uint256 creatorBalance = balanceOf(creator);
        uint256[] memory treatIds = new uint256[](creatorBalance);

        for (uint256 i = 0; i < creatorBalance; i++) {
            treatIds[i] = tokenOfOwnerByIndex(creator, i);
        }

        return treatIds;
    }

    /**
     * @dev Get treats by rarity
     * @param rarity Rarity string to filter by
     * @param offset Starting position for pagination
     * @param limit Maximum number of results
     * @return Array of token IDs with the specified rarity
     */
    function getTreatsByRarity(
        string memory rarity,
        uint256 offset,
        uint256 limit
    ) public view returns (uint256[] memory) {
        uint256 totalSupply = totalSupply();
        uint256 found = 0;

        // First pass: count matches after offset
        for (uint256 i = offset; i < totalSupply && found < limit; i++) {
            if (keccak256(bytes(treatMetadata[i].rarity)) == keccak256(bytes(rarity))) {
                found++;
            }
        }

        // Second pass: collect token IDs
        uint256[] memory results = new uint256[](found);
        found = 0;
        for (uint256 i = offset; i < totalSupply && found < limit; i++) {
            if (keccak256(bytes(treatMetadata[i].rarity)) == keccak256(bytes(rarity))) {
                results[found] = i;
                found++;
            }
        }

        return results;
    }

    /**
     * @dev Get treats by season
     * @param seasonId Season ID to filter by
     * @param offset Starting position for pagination
     * @param limit Maximum number of results
     * @return Array of token IDs from the specified season
     */
    function getTreatsBySeason(
        uint256 seasonId,
        uint256 offset,
        uint256 limit
    ) public view returns (uint256[] memory) {
        uint256 totalSupply = totalSupply();
        uint256 found = 0;

        // First pass: count matches after offset
        for (uint256 i = offset; i < totalSupply && found < limit; i++) {
            if (treatMetadata[i].seasonId == seasonId) {
                found++;
            }
        }

        // Second pass: collect token IDs
        uint256[] memory results = new uint256[](found);
        found = 0;
        for (uint256 i = offset; i < totalSupply && found < limit; i++) {
            if (treatMetadata[i].seasonId == seasonId) {
                results[found] = i;
                found++;
            }
        }

        return results;
    }

    /**
     * @dev Get statistics for a specific season
     * @param seasonId Season ID to get stats for
     * @return totalTreats Total treats created in season
     * @return uniqueCreators Number of unique creators in season
     * @return commonCount Number of common treats
     * @return rareCount Number of rare treats
     * @return epicCount Number of epic treats
     * @return legendaryCount Number of legendary treats
     */
    function getSeasonStats(uint256 seasonId) public view returns (
        uint256 totalTreats,
        uint256 uniqueCreators,
        uint256 commonCount,
        uint256 rareCount,
        uint256 epicCount,
        uint256 legendaryCount
    ) {
        uint256 totalSupply = totalSupply();

        for (uint256 i = 0; i < totalSupply; i++) {
            if (treatMetadata[i].seasonId == seasonId) {
                totalTreats++;

                // Count rarity distribution
                if (keccak256(bytes(treatMetadata[i].rarity)) == keccak256(bytes("Common"))) {
                    commonCount++;
                } else if (keccak256(bytes(treatMetadata[i].rarity)) == keccak256(bytes("Rare"))) {
                    rareCount++;
                } else if (keccak256(bytes(treatMetadata[i].rarity)) == keccak256(bytes("Epic"))) {
                    epicCount++;
                } else if (keccak256(bytes(treatMetadata[i].rarity)) == keccak256(bytes("Legendary"))) {
                    legendaryCount++;
                }
            }
        }

        // Note: uniqueCreators calculation is simplified here
        // In production, this would be better handled off-chain or with events
        uniqueCreators = totalTreats; // Placeholder
    }

    /**
     * @dev Get global contract statistics
     * @return totalTreats Total number of treats ever created
     * @return totalCommon Total common treats
     * @return totalRare Total rare treats
     * @return totalEpic Total epic treats
     * @return totalLegendary Total legendary treats
     */
    function getGlobalStats() public view returns (
        uint256 totalTreats,
        uint256 totalCommon,
        uint256 totalRare,
        uint256 totalEpic,
        uint256 totalLegendary
    ) {
        totalTreats = totalSupply();
        totalCommon = rarityTotals["Common"];
        totalRare = rarityTotals["Rare"];
        totalEpic = rarityTotals["Epic"];
        totalLegendary = rarityTotals["Legendary"];
    }

    // Override required functions for multiple inheritance.
    // OZ v5 replaced the old _beforeTokenTransfer/_burn hooks with a single
    // _update() that ERC721Enumerable and ERC721URIStorage both hook into
    // (for balance/index bookkeeping and clearing stored URIs on burn).
    function _update(address to, uint256 tokenId, address auth)
        internal
        override(ERC721, ERC721Enumerable)
        returns (address)
    {
        return super._update(to, tokenId, auth);
    }

    function _increaseBalance(address account, uint128 value)
        internal
        override(ERC721, ERC721Enumerable)
    {
        super._increaseBalance(account, value);
    }

    function tokenURI(uint256 tokenId)
        public
        view
        override(ERC721, ERC721URIStorage)
        returns (string memory)
    {
        return super.tokenURI(tokenId);
    }

    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(ERC721, ERC721Enumerable, ERC721URIStorage)
        returns (bool)
    {
        return super.supportsInterface(interfaceId);
    }
}
